export const UF_OPTIONS: string[] = Array.from(new Set(MUNICIPIOS_IBGE.map(m => m.uf))).sort();
export const MUNICIPIO_OPTIONS: NfseOption[] = MUNICIPIOS_IBGE.map(m => ({ value: `${m.codigo} - ${m.municipio}/${m.uf}`, label: `${m.codigo} - ${m.municipio}/${m.uf}` }));
export const PAIS_OPTIONS: string[] = PAISES_ISO2.map(p => `${p.iso2} - ${p.nome}`);
const normalizeTribNac = (value: string) => String(value || '').replace(/\D/g, '').padStart(6, '0');
const isNbsFinal = (value: string) => String(value || '').replace(/\D/g, '').length === 9;

export const SERVICO_NACIONAL_OPTIONS: NfseOption[] = SERVICOS_NACIONAIS.map(s => {
    const codigo = normalizeTribNac(s.codigo);
    return { value: `${codigo} - ${s.descricao}`, label: `${codigo} - ${s.descricao}` };
});
export const NBS_OPTIONS: NfseOption[] = NBS_LISTA
    .filter(n => isNbsFinal(n.codigo))
    .map(n => ({ value: `${formatarCodigoNBS(n.codigo)} - ${n.descricao}`, label: `${formatarCodigoNBS(n.codigo)} - ${n.descricao}` }));
export const INDICADOR_OPERACAO_OPTIONS: NfseOption[] = INDICADORES_OPERACAO_IBSCBS.map(i => ({ value: `${i.codigo} - ${i.tipoOperacao}`, label: `${i.codigo} - ${i.tipoOperacao}` }));
export const EVENTO_NFSE_OPTIONS: NfseOption[] = EVENTOS_NFSE.map(e => ({ value: `${e.codigo} - ${e.nome}`, label: `${e.codigo} - ${e.nome}` }));

const extractCodigo = (value: string) => String(value || '').split(' - ')[0].trim();
export const onlyCodigo = extractCodigo;
export const getMunicipioByCodigo = (value: string) => MUNICIPIOS_IBGE.find(m => m.codigo === extractCodigo(value));
export const getPaisByIso2 = (value: string) => PAISES_ISO2.find(p => p.iso2 === extractCodigo(value));
export const getServicoNacionalByCodigo = (value: string) => {
    const codigo = normalizeTribNac(extractCodigo(value));
    return SERVICOS_NACIONAIS.find(s => normalizeTribNac(s.codigo) === codigo);
};
export function formatarCodigoNBS(codigo: string): string {
    const n = String(codigo || '').replace(/\D/g, '');

    if (n.length !== 9) return codigo;

    return `${n.slice(0, 1)}.${n.slice(1, 5)}.${n.slice(5, 7)}.${n.slice(7, 9)}`;
}

export const getNbsByCodigo = (value?: string | null): NbsItem | undefined => {
    if (!value) return undefined;

    const codigoLimpo = String(value).replace(/\D/g, '');
    if (codigoLimpo.length !== 9) return undefined;

    const item = NBS_LISTA.find(
        n => String(n.codigo).replace(/\D/g, '') === codigoLimpo
    );

    return item
        ? {
            ...item,
            codigo: formatarCodigoNBS(item.codigo)
        }
        : undefined;
};
export const getIndicadorOperacaoByCodigo = (value: string) => INDICADORES_OPERACAO_IBSCBS.find(i => i.codigo === extractCodigo(value));
export const getRegraIncidenciaByServico = (value: string) => {
    const codigo = normalizeTribNac(extractCodigo(value));
    return REGRAS_INCIDENCIA_SERVICO.find(r => normalizeTribNac(r.codigo) === codigo);
};
